+const std = @import("std");
+const llama = @import("llama.zig");
+// Re-use the C types from llama module to avoid opaque type conflicts
+const c = llama.c;
+
+/// Cell state machine
+pub const CellState = enum {
+    idle, // Not active, ready for new request
+    thinking, // Actively generating tokens
+    waiting_for_tool, // Paused, waiting for external tool result
+    completed, // Generation finished
+};
+
+/// A Cell represents a single inference "thread" within the scheduler.
+/// Multiple Cells can run in parallel via continuous batching, each with
+/// its own seq_id in the KV cache.
+pub const Cell = struct {
+    id: u32, // Maps to llama seq_id
+    state: CellState,
+    buffer: std.ArrayListUnmanaged(u8), // Output token buffer
+    input_tokens: std.ArrayListUnmanaged(c.llama_token), // Pending input tokens
+    pos: u32, // Current position in context
+    max_tokens: u32, // Maximum tokens to generate
+    generated_count: u32, // Tokens generated so far
+    allocator: std.mem.Allocator,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, id: u32) Self {
+        return Self{
+            .id = id,
+            .state = .idle,
+            .buffer = .empty,
+            .input_tokens = .empty,
+            .pos = 0,
+            .max_tokens = 256,
+            .generated_count = 0,
+            .allocator = allocator,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.buffer.deinit(self.allocator);
+        self.input_tokens.deinit(self.allocator);
+    }
+
+    pub fn reset(self: *Self) void {
+        self.state = .idle;
+        self.buffer.clearRetainingCapacity();
+        self.input_tokens.clearRetainingCapacity();
+        self.pos = 0;
+        self.generated_count = 0;
+    }
+
+    /// Queue input tokens for this cell
+    pub fn queueInput(self: *Self, tokens: []const c.llama_token) !void {
+        try self.input_tokens.appendSlice(self.allocator, tokens);
+    }
+
+    /// Get the output text generated so far
+    pub fn getOutput(self: *const Self) []const u8 {
+        return self.buffer.items;
+    }
+};
+
+/// Scheduler options
+pub const SchedulerOptions = struct {
+    max_cells: u32 = 8, // Maximum parallel cells
+    context_per_cell: u32 = 512, // Context window per cell
+    batch_size: u32 = 512, // Max tokens per batch
+};
+
+/// The Scheduler manages multiple Cells running in parallel via continuous batching.
+/// It implements the Gather/Crunch/Dispatch loop pattern.
+pub const Scheduler = struct {
+    allocator: std.mem.Allocator,
+    model: *const llama.Model,
+    ctx: *c.llama_context,
+    sampler: *c.llama_sampler,
+    cells: []Cell,
+    batch: c.llama_batch,
+    opts: SchedulerOptions,
+    total_ctx: u32,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, model: *const llama.Model, opts: SchedulerOptions) !Self {
+        // Calculate total context needed
+        const total_ctx = opts.max_cells * opts.context_per_cell;
+
+        // Create llama context with full context size
+        var ctx_params = c.llama_context_default_params();
+        ctx_params.n_ctx = total_ctx;
+        ctx_params.n_batch = opts.batch_size;
+        ctx_params.n_threads = @intCast(std.Thread.getCpuCount() catch 4);
+        ctx_params.n_threads_batch = ctx_params.n_threads;
+
+        const ctx = c.llama_init_from_model(model.handle, ctx_params);
+        if (ctx == null) {
+            return error.FailedToCreateContext;
+        }
+        errdefer c.llama_free(ctx);
+
+        // Create sampler chain
+        const sampler_params = c.llama_sampler_chain_default_params();
+        const sampler = c.llama_sampler_chain_init(sampler_params);
+        if (sampler == null) {
+            c.llama_free(ctx);
+            return error.FailedToCreateSampler;
+        }
+        errdefer c.llama_sampler_free(sampler);
+
+        // Configure sampler with defaults
+        c.llama_sampler_chain_add(sampler, c.llama_sampler_init_temp(0.7));
+        c.llama_sampler_chain_add(sampler, c.llama_sampler_init_top_k(40));
+        c.llama_sampler_chain_add(sampler, c.llama_sampler_init_top_p(0.9, 1));
+        c.llama_sampler_chain_add(sampler, c.llama_sampler_init_dist(c.LLAMA_DEFAULT_SEED));
+
+        // Allocate cells
+        const cells = try allocator.alloc(Cell, opts.max_cells);
+        for (cells, 0..) |*cell, i| {
+            cell.* = Cell.init(allocator, @intCast(i));
+        }
+
+        // Create batch
+        const batch = c.llama_batch_init(@intCast(opts.batch_size), 0, @intCast(opts.max_cells));
+
+        return Self{
+            .allocator = allocator,
+            .model = model,
+            .ctx = ctx.?,
+            .sampler = sampler.?,
+            .cells = cells,
+            .batch = batch,
+            .opts = opts,
+            .total_ctx = total_ctx,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        c.llama_batch_free(self.batch);
+        for (self.cells) |*cell| {
+            cell.deinit();
+        }
+        self.allocator.free(self.cells);
+        c.llama_sampler_free(self.sampler);
+        c.llama_free(self.ctx);
+    }
+
+    /// Submit a prompt to a cell and start generation
+    pub fn submit(self: *Self, cell_id: u32, prompt: []const u8, max_tokens: u32) !void {
+        if (cell_id >= self.cells.len) {
+            return error.InvalidCellId;
+        }
+
+        var cell = &self.cells[cell_id];
+        if (cell.state != .idle) {
+            return error.CellBusy;
+        }
+
+        // Tokenize prompt
+        const vocab = self.model.getVocab();
+        var tokens: [4096]c.llama_token = undefined;
+        const n_tokens = c.llama_tokenize(
+            vocab,
+            prompt.ptr,
+            @intCast(prompt.len),
+            &tokens,
+            @intCast(tokens.len),
+            true, // add_special
+            true, // parse_special
+        );
+
+        if (n_tokens < 0) {
+            return error.TokenizationFailed;
+        }
+
+        // Clear memory (KV cache) for this cell's seq_id
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(cell_id), -1, -1);
+        }
+
+        // Queue tokens and start
+        cell.reset();
+        try cell.queueInput(tokens[0..@intCast(n_tokens)]);
+        cell.max_tokens = max_tokens;
+        cell.state = .thinking;
+    }
+
+    /// Find an idle cell, returns null if all cells are busy
+    pub fn findIdleCell(self: *Self) ?u32 {
+        for (self.cells, 0..) |*cell, i| {
+            if (cell.state == .idle) {
+                return @intCast(i);
+            }
+        }
+        return null;
+    }
+
+    /// Run one iteration of the scheduler loop (Gather/Crunch/Dispatch)
+    /// Returns true if any cells are still active
+    pub fn step(self: *Self) !bool {
+        var any_active = false;
+
+        // === GATHER ===
+        // Collect all pending tokens from active cells into the batch
+        self.batch.n_tokens = 0;
+        var batch_idx: usize = 0;
+
+        for (self.cells) |*cell| {
+            if (cell.state != .thinking) continue;
+            any_active = true;
+
+            // Add pending input tokens to batch
+            for (cell.input_tokens.items) |token| {
+                if (batch_idx >= self.opts.batch_size) break;
+
+                self.batch.token[batch_idx] = token;
+                self.batch.pos[batch_idx] = @intCast(cell.pos);
+                self.batch.n_seq_id[batch_idx] = 1;
+                self.batch.seq_id[batch_idx][0] = @intCast(cell.id);
+                self.batch.logits[batch_idx] = 0;
+
+                cell.pos += 1;
+                batch_idx += 1;
+            }
+
+            // Mark last token for logits (we'll sample from it)
+            if (batch_idx > 0 and cell.input_tokens.items.len > 0) {
+                self.batch.logits[batch_idx - 1] = 1;
+            }
+
+            cell.input_tokens.clearRetainingCapacity();
+        }
+
+        if (self.batch.n_tokens == 0) {
+            return any_active;
+        }
+
+        self.batch.n_tokens = @intCast(batch_idx);
+
+        // === CRUNCH ===
+        // Run the massive decode on all gathered tokens
+        if (c.llama_decode(self.ctx, self.batch) != 0) {
+            return error.DecodeFailed;
+        }
+
+        // === DISPATCH ===
+        // Sample next token for each active cell and dispatch results
+        const vocab = self.model.getVocab();
+
+        for (self.cells) |*cell| {
+            if (cell.state != .thinking) continue;
+
+            // Sample next token for this cell
+            const new_token = c.llama_sampler_sample(self.sampler, self.ctx, -1);
+
+            // Check for end of generation
+            if (c.llama_vocab_is_eog(vocab, new_token)) {
+                cell.state = .completed;
+                continue;
+            }
+
+            // Check token limit
+            cell.generated_count += 1;
+            if (cell.generated_count >= cell.max_tokens) {
+                cell.state = .completed;
+                continue;
+            }
+
+            // Check context limit for this cell
+            if (cell.pos >= self.opts.context_per_cell) {
+                cell.state = .completed;
+                continue;
+            }
+
+            // Convert token to string and append to buffer
+            var token_buf: [128]u8 = undefined;
+            const token_len = c.llama_token_to_piece(
+                vocab,
+                new_token,
+                &token_buf,
+                @intCast(token_buf.len),
+                0,
+                true,
+            );
+
+            if (token_len > 0) {
+                try cell.buffer.appendSlice(cell.allocator, token_buf[0..@intCast(token_len)]);
+            }
+
+            // Queue the new token for next iteration
+            try cell.queueInput(&[_]c.llama_token{new_token});
+        }
+
+        return any_active;
+    }
+
+    /// Run until all cells complete or reach max iterations
+    pub fn runUntilComplete(self: *Self, max_iterations: u32) !void {
+        var iterations: u32 = 0;
+        while (iterations < max_iterations) : (iterations += 1) {
+            const active = try self.step();
+            if (!active) break;
+        }
+    }
+
+    /// Get a cell by ID
+    pub fn getCell(self: *Self, cell_id: u32) ?*Cell {
+        if (cell_id >= self.cells.len) return null;
+        return &self.cells[cell_id];
+    }
+
+    /// Pause a cell (for tool execution)
+    pub fn pauseCell(self: *Self, cell_id: u32) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+        var cell = &self.cells[cell_id];
+        if (cell.state == .thinking) {
+            cell.state = .waiting_for_tool;
+        }
+    }
+
+    /// Resume a cell with tool result injected into context
+    pub fn resumeCell(self: *Self, cell_id: u32, tool_result: []const u8) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+        var cell = &self.cells[cell_id];
+        if (cell.state != .waiting_for_tool) return error.CellNotWaiting;
+
+        // Tokenize tool result
+        const vocab = self.model.getVocab();
+        var tokens: [4096]c.llama_token = undefined;
+        const n_tokens = c.llama_tokenize(
+            vocab,
+            tool_result.ptr,
+            @intCast(tool_result.len),
+            &tokens,
+            @intCast(tokens.len),
+            false, // don't add special tokens
+            true,
+        );
+
+        if (n_tokens < 0) {
+            return error.TokenizationFailed;
+        }
+
+        // Queue tool result tokens and resume
+        try cell.queueInput(tokens[0..@intCast(n_tokens)]);
+        cell.state = .thinking;
+    }
+};
+
+// Tests
+test "cell lifecycle" {
+    const allocator = std.testing.allocator;
+
+    var cell = Cell.init(allocator, 0);
+    defer cell.deinit();
+
+    try std.testing.expect(cell.state == .idle);
+    try std.testing.expect(cell.id == 0);
+    try std.testing.expect(cell.pos == 0);
+}
